SELECT TPS.ID,TPS.PROCESS_DETAIL_CODE,DECODE(SD.DEPT_LEVEL,2,SD.ID,4,PSD.ID,NULL) DEPT_ID, TPS.SALARY_TYPE_CODE,TPS.SALARY_STATUS_CODE,TPS.DEPT_NAME,TPS.USER_BY_NAME, DECODE(SD.DEPT_LEVEL,2,SD.DEPT_NAME,4,PSD.DEPT_NAME,NULL) DEPT_NM,TPS.TON, TPS.COMPANY_ID,TPS.WORK_DATE,TPS.CLASS_NAME FROM T_PRD_SALARY TPS LEFT JOIN SYS_DEPT SD ON TPS.DEPT_ID = SD.ID LEFT JOIN SYS_DEPT PSD ON SD.PARENT_ID = PSD.ID WHERE TPS.WORK_DATE >= TO_DATE (#{startDay,jdbcType=VARCHAR}, 'YYYY-MM-DD') AND TPS.WORK_DATE <= TO_DATE (#{endDay,jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND DECODE(SD.DEPT_LEVEL,2,SD.ID,4,PSD.ID,NULL) = #{deptId, jdbcType=BIGINT}
AND TPS.SALARY_STATUS_CODE = #{salaryStatusCode, jdbcType=VARCHAR}
ORDER BY TPS.CREATE_TIME DESC

SELECT TPS.ID,TPS.PROCESS_DETAIL_CODE,DECODE(SD.DEPT_LEVEL,2,SD.ID,4,PSD.ID,NULL) DEPT_ID,
TPS.SALARY_TYPE_CODE,TPS.SALARY_STATUS_CODE,TPS.DEPT_NAME,TPS.USER_BY_NAME,
DECODE(SD.DEPT_LEVEL,2,SD.DEPT_NAME,4,PSD.DEPT_NAME,NULL) DEPT_NM,TPS.TON,
TPS.COMPANY_ID,TPS.WORK_DATE,TPS.CLASS_NAME
FROM T_PRD_SALARY TPS
LEFT JOIN SYS_DEPT SD ON TPS.DEPT_ID = SD.ID
LEFT JOIN SYS_DEPT PSD ON SD.PARENT_ID = PSD.ID
WHERE SALARY_TYPE_CODE != '99'

        AND DECODE(SD.DEPT_LEVEL,2,SD.ID,4,PSD.ID,NULL) = #{deptId, jdbcType=BIGINT}


        AND TPS.SALARY_STATUS_CODE = #{salaryStatusCode, jdbcType=VARCHAR}


        AND TPS.WORK_DATE >=  #{startDate,jdbcType=TIMESTAMP}


        AND TPS.WORK_DATE <=  #{endDate,jdbcType=TIMESTAMP}


        AND TPS.CLASS_CODE = #{classCode, jdbcType=VARCHAR}


        AND TPS.COMPANY_ID = #{companyId,jdbcType=BIGINT}


        AND TPS.SALARY_TYPE_CODE = #{salaryTypeCode,jdbcType=VARCHAR}


    AND TPS.IS_ODD = #{isOdd, jdbcType=VARCHAR}

ORDER BY TPS.CREATE_TIME DESC

SELECT A1.COMPANY_ID, A1.COMPANY_NAME, A1.PROCESS_DETAIL_CODE, A1.PROCESS_DETAIL_NAME, A1.PIECE_PROJECT_CODE, A1.PIECE_PROJECT_NAME, CAST ( A2.PROCESS_CODE AS VARCHAR2 (20) ) AS PROCESS_CODE, CAST ( A2.PROCESS_NAME AS VARCHAR2 (20) ) AS PROCESS_NAME, A2.CARGO_INFO_ID, A2.CARGO_CODE, A2.CARGO_NAME, A1.PRICE, A1.SALARY_PRICE_ID, SUM (A1.TON) TON, SUM (A1.AMOUNT) AMOUNT FROM T_PRD_SALARY A1 LEFT JOIN T_PRD_WORK_TICKET_DETAIL A2 ON A1.WORK_TICKET_DETAIL_ID = A2. ID WHERE A1.WORK_DATE >= #{startDate,jdbcType=TIMESTAMP} AND A1.WORK_DATE <= #{endDate,jdbcType=TIMESTAMP} AND A2.PROCESS_CODE IS NOT NULL
AND A2.DEPT_ID = #{deptId,jdbcType=BIGINT}
AND A1.COMPANY_ID = #{companyId,jdbcType=BIGINT}
AND A1.CLASS_CODE = #{classCode,jdbcType=VARCHAR}
AND A1.SALARY_TYPE_CODE = #{salaryTypeCode,jdbcType=VARCHAR}
AND A1.SALARY_STATUS_CODE = 20 GROUP BY A1.COMPANY_ID, A1.COMPANY_NAME, A1.PROCESS_DETAIL_CODE, A1.PROCESS_DETAIL_NAME, A1.PIECE_PROJECT_CODE, A1.PIECE_PROJECT_NAME, A2.PROCESS_CODE, A2.PROCESS_NAME, A2.CARGO_INFO_ID, A2.CARGO_CODE, A2.CARGO_NAME, A1.PRICE, A1.SALARY_PRICE_ID UNION ALL SELECT A1.COMPANY_ID, A1.COMPANY_NAME, A3.PROCESS_DETAIL_CODE, A3.PROCESS_DETAIL_NAME, A1.PIECE_PROJECT_CODE, A1.PIECE_PROJECT_NAME, CAST ( A2.PROCESS_CODE AS VARCHAR2 (20) ) AS PROCESS_CODE, CAST ( A2.PROCESS_NAME AS VARCHAR2 (20) ) AS PROCESS_NAME, A3.CARGO_INFO_ID, A3.CARGO_CODE, A3.CARGO_NAME, A1.PRICE, A1.SALARY_PRICE_ID, SUM (A1.TON) TON, SUM (A1.AMOUNT) AMOUNT FROM T_PRD_SALARY A1 LEFT JOIN T_PRD_WORK_TICKET A2 ON A1.WORK_TICKET_ID = A2. ID LEFT JOIN T_PRD_WORK_TICKET_DETAIL A3 ON A3.WORK_TICKET_ID = A2. ID WHERE A1.WORK_DATE >= #{startDate,jdbcType=TIMESTAMP} AND A1.WORK_DATE <= #{endDate,jdbcType=TIMESTAMP} AND A2.PROCESS_CODE IS NOT NULL
AND A2.DEPT_ID IN ( SELECT ID FROM SYS_DEPT WHERE PARENT_ID = #{deptId,jdbcType=BIGINT} )
AND A1.COMPANY_ID = #{companyId,jdbcType=BIGINT}
AND A1.CLASS_CODE = #{classCode,jdbcType=VARCHAR}
AND A1.SALARY_TYPE_CODE = #{salaryTypeCode,jdbcType=VARCHAR}
AND A1.SALARY_STATUS_CODE = 20 GROUP BY A1.COMPANY_ID, A1.COMPANY_NAME, A3.PROCESS_DETAIL_CODE, A3.PROCESS_DETAIL_NAME, A1.PIECE_PROJECT_CODE, A1.PIECE_PROJECT_NAME, A2.PROCESS_CODE, A2.PROCESS_NAME, A3.CARGO_INFO_ID, A3.CARGO_CODE, A3.CARGO_NAME, A1.PRICE, A1.SALARY_PRICE_ID UNION ALL SELECT A1.COMPANY_ID, A1.COMPANY_NAME, A1.PROCESS_DETAIL_CODE, A1.PROCESS_DETAIL_NAME, A1.PIECE_PROJECT_CODE, A1.PIECE_PROJECT_NAME, CAST ( A1.PROCESS_CODE AS VARCHAR2 (20) ) AS PROCESS_CODE, CAST ( A1.PROCESS_NAME AS VARCHAR2 (20) ) AS PROCESS_NAME, NULL AS CARGO_INFO_ID, NULL AS CARGO_CODE, NULL AS CARGO_NAME, A1.PRICE, A1.SALARY_PRICE_ID, SUM (A1.TON) TON, SUM (A1.AMOUNT) AMOUNT FROM T_PRD_SALARY A1 LEFT JOIN T_PRD_ODD_WORK_PLAN TPOWP ON A1.ODD_PLAN_ID = TPOWP.ID WHERE A1.WORK_DATE >= #{startDate,jdbcType=TIMESTAMP} AND A1.WORK_DATE <= #{endDate,jdbcType=TIMESTAMP} AND A1.IS_ODD = '1'
AND TPOWP.WORK_DEPT_ID = #{deptId,jdbcType=BIGINT}
AND A1.COMPANY_ID = #{companyId,jdbcType=BIGINT}
AND A1.CLASS_CODE = #{classCode,jdbcType=VARCHAR}
AND A1.SALARY_TYPE_CODE = #{salaryTypeCode,jdbcType=VARCHAR}
AND A1.SALARY_STATUS_CODE = 20 GROUP BY A1.COMPANY_ID, A1.COMPANY_NAME, A1.PROCESS_DETAIL_CODE, A1.PROCESS_DETAIL_NAME, A1.PIECE_PROJECT_CODE, A1.PIECE_PROJECT_NAME, A1.PROCESS_CODE, A1.PROCESS_NAME, A1.PRICE, A1.SALARY_PRICE_ID

        SELECT
	        PRICE "price",
	        to_char(ID) "id"
        FROM
	        M_PIECE_PRICE
        WHERE
	        COMPANY_ID = #{companyId,jdbcType=BIGINT}
	    AND SALARY_TYPE_CODE = #{salaryTypeCode,jdbcType=VARCHAR}
        AND PIECE_PROJECT_CODE = #{pieceProjectCode,jdbcType=VARCHAR}
        AND WORK_PROCESS_CHILD_ID IN (SELECT ID FROM M_WORK_PROCESS WHERE PROCESS_CD = #{processDetailCode,jdbcType=VARCHAR})

