UPDATE T_PRD_SALARY
SET
SALARY_STATUS_CODE = #{item.salaryStatusCode,jdbcType=VARCHAR},
SALARY_STATUS_NAME = #{item.salaryStatusName,jdbcType=VARCHAR},
PRICE = #{item.price,jdbcType=DECIMAL},
SALARY_PRICE_ID = #{item.salaryPriceId,jdbcType=BIGINT},
AMOUNT = #{item.amount,jdbcType=DECIMAL},
EXAMINE_BY = #{item.createBy,jdbcType=BIGINT},
EXAMINE_BY_NAME = #{item.createByName,jdbcType=VARCHAR},
EXAMINE_TIME = #{item.createTime,jdbcType=TIMESTAMP}
WHERE ID = #{item.id}
AND SALARY_STATUS_CODE = #{item.salaryStatusCodeWhere,jdbcType=VARCHAR}

    ;

mapper.update:
UPDATE T_PRD_SALARY
SET
SALARY_STATUS_CODE = #{salaryStatusCode,jdbcType=VARCHAR},
SALARY_STATUS_NAME = #{salaryStatusName,jdbcType=VARCHAR},
EXAMINE_BY_HR = #{examineByHr,jdbcType=BIGINT},
EXAMINE_BY_NAME_HR = #{examineByNameHr,jdbcType=VARCHAR},
EXAMINE_TIME_HR = #{examineTimeHr,jdbcType=TIMESTAMP}
WHERE ID IN (
    SELECT TPS.ID
    FROM T_PRD_SALARY TPS
    LEFT JOIN SYS_DEPT SD ON TPS.DEPT_ID = SD.ID
    LEFT JOIN SYS_DEPT PSD ON SD.PARENT_ID = PSD.ID
    WHERE TPS.WORK_DATE >= #{startDate,jdbcType=TIMESTAMP}
AND TPS.WORK_DATE <= #{endDate,jdbcType=TIMESTAMP}

    AND TPS.DEPT_ID IN (
    SELECT
    ID
    FROM
    SYS_DEPT
    WHERE
    PARENT_ID = #{deptId,jdbcType=BIGINT}
    )


    AND TPS.COMPANY_ID = #{companyId,jdbcType=BIGINT}


    AND TPS.CLASS_CODE = #{classCode,jdbcType=VARCHAR}


    AND TPS.SALARY_TYPE_CODE = #{salaryTypeCode,jdbcType=VARCHAR}

)
AND SALARY_STATUS_CODE = #{salaryStatusCodeWhere,jdbcType=VARCHAR}

